const inputs = $input.first().json.inputs
const systemPrompt = $input.first().json.systemPrompt;

function createBatchRequestLine(input, index) {
  return {
    custom_id: `${index}_${Date.now()}`,
    method: "POST",
    url: "/v1/responses",
    body: {
      model: "gpt-5-mini",
      instructions: systemPrompt,
      input,
    }
  };
}

const jsonlContent = inputs
  .map((input, index) => JSON.stringify(createBatchRequestLine(input, index)))
  .join('\n');

// Convert to base64 for binary
const base64Content = Buffer.from(jsonlContent, 'utf-8').toString('base64');

// Return with binary data - ready for HTTP Request!
return [{
  binary: {
    data: {
      data: base64Content,
      mimeType: 'application/x-ndjson',
      fileName: 'batch_input.jsonl'
    }
  }
}];

const base64Content = $input.first().json.data;

const jsonlContent = Buffer.from(base64Content, 'base64').toString('utf-8');

const lines = jsonlContent
  .split('\n')
  .filter(line => line.trim())
  .map(line => {
    try {
      return JSON.parse(line);
    } catch (e) {
      return null;
    }
  })
  .filter(line => line !== null);

// Extract answers from each line
const results = [];
let parsed = 0;
let errors = 0;

for (const line of lines) {
  try {
    if (line.error || line.response?.status_code !== 200) {
      errors++;
      continue;
    }

    const output = line.response?.body?.output || [];
    const messageOutput = output.find(o => o.type === 'message');
    const text = messageOutput?.content?.[0]?.text;

    if (!text) {
      errors++;
      continue;
    }

    results.push(text);
    parsed++;
  } catch (e) {
    errors++;
  }
}

// Get batch metadata from the earlier node
const batch = $('If status = completed').first().json;

return [{
  json: {
    id: batch.id,
    status: batch.status,
    output_file_id: batch.output_file_id,
    result: results,
    parsed,
    errors
  }
}];
